import{_ as i,a,b as n}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as t,o,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Authentication اور Login Device Management","description":"","frontmatter":{},"headers":[],"relativePath":"ur/Safety/authentication-and-login-devices.md","filePath":"ur/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),d={name:"ur/Safety/authentication-and-login-devices.md"};function r(c,e,u,p,m,h){return o(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="authentication-اور-login-device-management" tabindex="-1">Authentication اور Login Device Management <a class="header-anchor" href="#authentication-اور-login-device-management" aria-label="Permalink to &quot;Authentication اور Login Device Management&quot;">​</a></h1><p><code>Authentication Management</code> اور <code>Login Device Management</code> آپ کے ImgBed admin panel، public upload entry، اور WebDAV access کی حفاظت کرتے ہیں۔</p><p>اس صفحے سے access credentials set کریں، signed-in devices دیکھیں، اور ضرورت پڑنے پر پرانے sessions revoke کریں۔</p><h2 id="کہاں-configure-کریں" tabindex="-1">کہاں Configure کریں <a class="header-anchor" href="#کہاں-configure-کریں" aria-label="Permalink to &quot;کہاں Configure کریں&quot;">​</a></h2><p>admin panel کھولیں، پھر جائیں:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings</span></span></code></pre></div><p>اس page میں دو main areas ہیں:</p><ul><li>Authentication Management</li><li>Login Device Management</li></ul><p><img src="'+i+'" alt="Authentication management" loading="lazy"></p><h2 id="authentication-management-کیا-کرتا-ہے" tabindex="-1">Authentication Management کیا کرتا ہے <a class="header-anchor" href="#authentication-management-کیا-کرتا-ہے" aria-label="Permalink to &quot;Authentication Management کیا کرتا ہے&quot;">​</a></h2><p>Authentication Management access credentials محفوظ کرتا ہے۔</p><p>اس کی دو types ہیں:</p><ul><li>User-side authentication</li><li>Admin-side authentication</li></ul><h2 id="user-side-authentication" tabindex="-1">User-Side Authentication <a class="header-anchor" href="#user-side-authentication" aria-label="Permalink to &quot;User-Side Authentication&quot;">​</a></h2><p>User-side authentication upload password ہے۔</p><p>upload password set ہونے کے بعد عام visitors کو upload page استعمال کرنے سے پہلے password درج کرنا ہوگا۔ یہ اس وقت مفید ہے جب آپ public upload page ہر کسی کے لیے کھلا نہیں رکھنا چاہتے۔</p><p><img src="'+a+'" alt="User login page" loading="lazy"></p><h3 id="upload-password-set-کرنا" tabindex="-1">Upload Password Set کرنا <a class="header-anchor" href="#upload-password-set-کرنا" aria-label="Permalink to &quot;Upload Password Set کرنا&quot;">​</a></h3><p>جب upload password configured ہو:</p><ul><li>visitors کو upload page استعمال کرنے سے پہلے password درج کرنا ہوگا۔</li><li>upload صرف password قبول ہونے کے بعد دستیاب ہوگا۔</li><li>اگر user-side device sessions enabled ہوں تو ImgBed اس user-side device کو record کرے گا۔</li></ul><p>upload password تبدیل کرنے سے پرانے user-side sessions invalid ہو جاتے ہیں۔ visitors کو نیا password دوبارہ درج کرنا ہوگا۔</p><h2 id="admin-side-authentication" tabindex="-1">Admin-Side Authentication <a class="header-anchor" href="#admin-side-authentication" aria-label="Permalink to &quot;Admin-Side Authentication&quot;">​</a></h2><p>Admin-side authentication admin username اور password استعمال کرتا ہے۔</p><p>یہ admin panel کی حفاظت کرتا ہے۔ production use کے لیے اسے ہمیشہ configure کرنا چاہیے۔</p><p><img src="'+n+'" alt="Admin login page" loading="lazy"></p><h3 id="admin-credentials-set-کرنا" tabindex="-1">Admin Credentials Set کرنا <a class="header-anchor" href="#admin-credentials-set-کرنا" aria-label="Permalink to &quot;Admin Credentials Set کرنا&quot;">​</a></h3><p>جب admin username اور password configured ہوں:</p><ul><li>admin panel کھولنے کے لیے login ضروری ہوگا۔</li><li>successful login ایک admin device record بناتا ہے۔</li><li>Login Device Management میں آپ devices review، clean up، یا force offline کر سکتے ہیں۔</li></ul><p>admin username یا password تبدیل کرنے سے پرانے admin sessions invalid ہو جاتے ہیں۔ آپ کو دوبارہ sign in کرنا ہوگا۔</p><h2 id="login-device-management-کیا-کرتا-ہے" tabindex="-1">Login Device Management کیا کرتا ہے <a class="header-anchor" href="#login-device-management-کیا-کرتا-ہے" aria-label="Permalink to &quot;Login Device Management کیا کرتا ہے&quot;">​</a></h2><p>Login Device Management signed-in devices دکھاتا ہے۔</p><p>یہ چیک کرنے میں مدد دیتا ہے:</p><ul><li>کن devices نے admin panel access کیا۔</li><li>کن devices نے user-side upload page access کیا۔</li><li>کون سے WebDAV clients connect ہوئے۔</li><li>device session ابھی valid ہے یا نہیں۔</li><li>پرانے devices کو force offline کرنا چاہیے یا نہیں۔</li></ul><p>page میں تین tabs ہیں:</p><ul><li>Admin</li><li>User</li><li>WebDAV</li></ul><h2 id="global-cookie-security" tabindex="-1">Global Cookie Security <a class="header-anchor" href="#global-cookie-security" aria-label="Permalink to &quot;Global Cookie Security&quot;">​</a></h2><p>Login Device Management کے اوپر آپ global cookie behavior configure کر سکتے ہیں۔</p><h3 id="user-cookie-lifetime" tabindex="-1">User Cookie Lifetime <a class="header-anchor" href="#user-cookie-lifetime" aria-label="Permalink to &quot;User Cookie Lifetime&quot;">​</a></h3><p>یہ کنٹرول کرتا ہے کہ user-side login کتنے دن active رہ سکتا ہے۔</p><p>مثلاً اگر آپ اسے 14 days set کریں، تو visitors کو عموماً 14 دن کے اندر upload password دوبارہ درج نہیں کرنا پڑے گا۔</p><h3 id="admin-cookie-lifetime" tabindex="-1">Admin Cookie Lifetime <a class="header-anchor" href="#admin-cookie-lifetime" aria-label="Permalink to &quot;Admin Cookie Lifetime&quot;">​</a></h3><p>یہ کنٹرول کرتا ہے کہ admin login کتنے دن active رہ سکتا ہے۔</p><p>مثلاً اگر 14 days set کریں، تو administrators کو عموماً 14 دن کے اندر دوبارہ sign in نہیں کرنا پڑے گا۔</p><h3 id="secure-mode" tabindex="-1">Secure Mode <a class="header-anchor" href="#secure-mode" aria-label="Permalink to &quot;Secure Mode&quot;">​</a></h3><p>Secure mode enabled ہو تو browsers login cookies صرف HTTPS پر send کرتے ہیں۔</p><p>production HTTPS sites کے لیے اسے enable کریں۔ local HTTP testing کے لیے enable نہ کریں، ورنہ &quot;login succeeded, but refresh logs me out&quot; جیسا behavior آ سکتا ہے۔</p><h2 id="admin-login-devices" tabindex="-1">Admin Login Devices <a class="header-anchor" href="#admin-login-devices" aria-label="Permalink to &quot;Admin Login Devices&quot;">​</a></h2><p>Admin tab وہ devices دکھاتا ہے جنہوں نے admin panel میں sign in کیا۔</p><p>device records صرف اس وقت ظاہر ہوتے ہیں جب admin credentials configured ہوں اور admin panel login کے ذریعے access کیا جائے۔</p><p>ہر device card یہ دکھا سکتا ہے:</p><ul><li>device اور browser information</li><li>first login IP</li><li>last active IP</li><li>login time</li><li>last active time</li><li>expiration time</li><li>current status</li></ul><p>اگر کوئی device unfamiliar لگے تو <code>Force Offline</code> سے اسے invalidate کریں۔</p><h2 id="clean-up-old-devices" tabindex="-1">Clean Up Old Devices <a class="header-anchor" href="#clean-up-old-devices" aria-label="Permalink to &quot;Clean Up Old Devices&quot;">​</a></h2><p><code>Clean Up Old Devices</code> current tab میں پرانے login records کو bulk میں remove کرتا ہے۔</p><p>اسے اس وقت استعمال کریں جب آپ کو شک ہو کہ پرانے sessions دوسرے devices پر ابھی active ہو سکتے ہیں۔</p><h2 id="force-offline" tabindex="-1">Force Offline <a class="header-anchor" href="#force-offline" aria-label="Permalink to &quot;Force Offline&quot;">​</a></h2><p><code>Force Offline</code> ایک device session کو invalidate کرتا ہے۔</p><p>device force offline ہونے کے بعد:</p><ul><li>Admin devices کو دوبارہ sign in کرنا ہوگا۔</li><li>User-side devices کو upload password دوبارہ درج کرنا ہوگا۔</li><li>WebDAV clients کو دوبارہ authenticate کرنا ہوگا۔</li></ul><p>Expired یا invalid devices بھی remove کیے جا سکتے ہیں۔</p><h2 id="sign-out-current-device" tabindex="-1">Sign Out Current Device <a class="header-anchor" href="#sign-out-current-device" aria-label="Permalink to &quot;Sign Out Current Device&quot;">​</a></h2><p>current device card پر <code>Current Device</code> mark ہوتا ہے۔</p><p>current device سے sign out کرنے کے بعد:</p><ul><li>current admin session sign out ہو جاتا ہے۔</li><li>current user-side session sign out ہو جاتا ہے۔</li></ul><p>اس area کا استعمال جاری رکھنے سے پہلے آپ کو دوبارہ sign in کرنا ہوگا۔</p>',65)])])}const b=t(d,[["render",r]]);export{f as __pageData,b as default};
